1110 static SmallVector<int, 8> getSpliceMask(int64_t Imm, unsigned NumElts) {
1111   unsigned Idx = (NumElts + Imm) % NumElts;
1112   SmallVector<int, 8> Mask;
1113   for (unsigned I = 0; I < NumElts; ++I)
1114     Mask.push_back(Idx + I);
1115   return Mask;
