4685         // This means the extract is not influenced by the insert, and we can
4686         // replace the aggregate operand of the extract with the aggregate
4687         // operand of the insert. i.e., replace
4688         // %I = insertvalue { i32, { i32 } } %A, { i32 } { i32 42 }, 1
4689         // %E = extractvalue { i32, { i32 } } %I, 0
