4786 /// Return 'true' if the given typeinfo will match anything.
4787 static bool isCatchAll(EHPersonality Personality, Constant *TypeInfo) {
4788   switch (Personality) {
4789   case EHPersonality::GNU_C:
4790   case EHPersonality::GNU_C_SjLj:
4791   case EHPersonality::Rust:
4792     // The GCC C EH and Rust personality only exists to support cleanups, so
4793     // it's not clear what the semantics of catch clauses are.
4794     return false;
4795   case EHPersonality::Unknown:
4796     return false;
4797   case EHPersonality::GNU_Ada:
4798     // While __gnat_all_others_value will match any Ada exception, it doesn't
4799     // match foreign exceptions (or didn't, before gcc-4.7).
4800     return false;
4801   case EHPersonality::GNU_CXX:
4802   case EHPersonality::GNU_CXX_SjLj:
4803   case EHPersonality::GNU_ObjC:
4804   case EHPersonality::MSVC_X86SEH:
4805   case EHPersonality::MSVC_TableSEH:
4806   case EHPersonality::MSVC_CXX:
4807   case EHPersonality::CoreCLR:
4808   case EHPersonality::Wasm_CXX:
4809   case EHPersonality::XL_CXX:
4810   case EHPersonality::ZOS_CXX:
4811     return TypeInfo->isNullValue();
4812   }
4813   llvm_unreachable("invalid enum");
4814 }
