4823 Instruction *InstCombinerImpl::visitLandingPadInst(LandingPadInst &LI) {
4824   // The logic here should be correct for any real-world personality function.
4825   // However if that turns out not to be true, the offending logic can always
4826   // be conditioned on the personality function, like the catch-all logic is.
4827   EHPersonality Personality =
4828       classifyEHPersonality(LI.getParent()->getParent()->getPersonalityFn());
4829 
4830   // Simplify the list of clauses, eg by removing repeated catch clauses
4831   // (these are often created by inlining).
4832   bool MakeNewInstruction = false; // If true, recreate using the following:
4833   SmallVector<Constant *, 16> NewClauses; // - Clauses for the new instruction;
4834   bool CleanupFlag = LI.isCleanup();   // - The new instruction is a cleanup.
4835 
4836   SmallPtrSet<Value *, 16> AlreadyCaught; // Typeinfos known caught already.
4837   for (unsigned i = 0, e = LI.getNumClauses(); i != e; ++i) {
4838     bool isLastClause = i + 1 == e;
4839     if (LI.isCatch(i)) {
4840       // A catch clause.
4841       Constant *CatchClause = LI.getClause(i);
4842       Constant *TypeInfo = CatchClause->stripPointerCasts();
4843 
4844       // If we already saw this clause, there is no point in having a second
4845       // copy of it.
4846       if (AlreadyCaught.insert(TypeInfo).second) {
4847         // This catch clause was not already seen.
4848         NewClauses.push_back(CatchClause);
4849       } else {
4850         // Repeated catch clause - drop the redundant copy.
4851         MakeNewInstruction = true;
4852       }
4853 
4854       // If this is a catch-all then there is no point in keeping any following
4855       // clauses or marking the landingpad as having a cleanup.
4856       if (isCatchAll(Personality, TypeInfo)) {
4857         if (!isLastClause)
4858           MakeNewInstruction = true;
4859         CleanupFlag = false;
4860         break;
4861       }
4862     } else {
4863       // A filter clause.  If any of the filter elements were already caught
4864       // then they can be dropped from the filter.  It is tempting to try to
4865       // exploit the filter further by saying that any typeinfo that does not
4866       // occur in the filter can't be caught later (and thus can be dropped).
4867       // However this would be wrong, since typeinfos can match without being
4868       // equal (for example if one represents a C++ class, and the other some
4869       // class derived from it).
4870       assert(LI.isFilter(i) && "Unsupported landingpad clause!");
4871       Constant *FilterClause = LI.getClause(i);
4872       ArrayType *FilterType = cast<ArrayType>(FilterClause->getType());
4873       unsigned NumTypeInfos = FilterType->getNumElements();
4874 
4875       // An empty filter catches everything, so there is no point in keeping any
4876       // following clauses or marking the landingpad as having a cleanup.  By
4877       // dealing with this case here the following code is made a bit simpler.
4878       if (!NumTypeInfos) {
4879         NewClauses.push_back(FilterClause);
4880         if (!isLastClause)
4881           MakeNewInstruction = true;
4882         CleanupFlag = false;
4883         break;
4884       }
4885 
4886       bool MakeNewFilter = false; // If true, make a new filter.
4887       SmallVector<Constant *, 16> NewFilterElts; // New elements.
4888       if (isa<ConstantAggregateZero>(FilterClause)) {
4889         // Not an empty filter - it contains at least one null typeinfo.
4890         assert(NumTypeInfos > 0 && "Should have handled empty filter already!");
4891         Constant *TypeInfo =
4892           Constant::getNullValue(FilterType->getElementType());
4893         // If this typeinfo is a catch-all then the filter can never match.
4894         if (isCatchAll(Personality, TypeInfo)) {
4895           // Throw the filter away.
4896           MakeNewInstruction = true;
4897           continue;
4898         }
